local function wn(az,uo)
  local vd,f=0,1
  while az>0 or uo>0 do
    vd=vd+(((az%2)+(uo%2))%2)*f
    az=math.floor(az/2)
    uo=math.floor(uo/2)
    f=f*2
  end
  return vd
end
